using System.ComponentModel;using System.Diagnostics.CodeAnalysis;using System.Text;using Microsoft.SemanticKernel;namespace Agent;public sealed class SkillLearningPlugin(SkillIndexHolder holder){	const string defaultRelativeFile = "SKILL.md";	static bool TryResolveUnderRoot(string skillRootFull, string relativePath, out string absoluteFile, out string error)	{		absoluteFile = string.Empty;		error = string.Empty;		var combined = Path.GetFullPath(Path.Combine(skillRootFull, relativePath));		var rootWithSep = skillRootFull.EndsWith(Path.DirectorySeparatorChar)			? skillRootFull			: skillRootFull + Path.DirectorySeparatorChar;		if(!combined.StartsWith(rootWithSep, StringComparison.OrdinalIgnoreCase)		   && !string.Equals(combined, skillRootFull, StringComparison.OrdinalIgnoreCase))		{			error = "错误：路径越界，必须位于技能根目录内。";			return false;		}		if(Directory.Exists(combined))		{			error = "错误：目标是目录而非文件。";			return false;		}		if(!File.Exists(combined))		{			error = $"错误：文件不存在：{relativePath}";			return false;		}		absoluteFile = combined;		return true;	}	static string FormatDirectoryListing(string skillRootFull)	{		if(!Directory.Exists(skillRootFull))			return"(无法列出：根目录不存在)";		try		{			var lines = Directory				.EnumerateFileSystemEntries(skillRootFull, "*", SearchOption.AllDirectories)				.Select(fullPath => Path.GetRelativePath(skillRootFull, fullPath))				.OrderBy(static relative => relative, StringComparer.OrdinalIgnoreCase)				.ToArray();			return lines.Length == 0? "(空目录)" : string.Join(Environment.NewLine, lines);		}		catch(IOException exception) { return$"(列出失败：{exception.Message})"; }		catch(UnauthorizedAccessException exception) { return$"(列出失败：{exception.Message})"; }	}	[SuppressMessage("ReSharper", "InconsistentNaming"), KernelFunction("learn_skill"),	 Description("读取技能"),]	// ReSharper disable once UnusedMember.Global	public string LearnSkill(		[Description("技能id，与系统消息中列表一致")]string skill_id,		[Description("相对技能根目录的文件路径，缺省表示 SKILL.md")]		string? relative_path = null)	{		if(string.IsNullOrWhiteSpace(skill_id))			return"错误：skill_id 不能为空。";		if(!holder.Index.TryGetValue(skill_id.Trim(), out var summary))			return$"错误：未找到技能 id「{skill_id}」。请使用系统消息中列出的 id。";		Console.WriteLine($"[learn {skill_id} {relative_path}]");		var skillRoot = Path.GetFullPath(summary.Path);		var useImplicitDefault = string.IsNullOrWhiteSpace(relative_path);		var relativeSegment = useImplicitDefault? defaultRelativeFile : relative_path!.Trim().TrimStart('/', '\\');		if(string.IsNullOrEmpty(relativeSegment))			relativeSegment = defaultRelativeFile;		if(!TryResolveUnderRoot(skillRoot, relativeSegment, out var absoluteFile, out var resolveError))			return resolveError;		string fileText;		try { fileText = File.ReadAllText(absoluteFile, Encoding.UTF8); }		catch(IOException exception) { return$"错误：无法读取文件：{exception.Message}"; }		catch(UnauthorizedAccessException exception) { return$"错误：无权读取文件：{exception.Message}"; }		if(!useImplicitDefault)			return fileText;		var builder = new StringBuilder();		builder.AppendLine("### 技能目录结构（相对技能根目录）");		builder.AppendLine(FormatDirectoryListing(skillRoot));		builder.AppendLine($"### {relativeSegment} 全文");		builder.AppendLine(fileText);		builder.AppendLine();		return builder.ToString();	}}